"""
MKT Context Commentary — Acts chapters 12–13
Run: python3 scripts/zc-context-acts-12-13.py

Source data used:
- data/interlinear/acts.json
- data/translation/draft/mediating/acts.json
- data/commentary/mkt-context/acts.json (ch13 v1 already present)

Key decisions in this range:
- Herod Agrippa I (ch12): extensively documented by Josephus (Ant. 18-19);
  the angel-struck death is confirmed in Josephus Ant. 19.8.2, making this one
  of the strongest points of external corroboration in Acts.
- Sergius Paulus (ch13:7): attested in inscriptions from Cyprus and Rome;
  his family is known from Roman epigraphic sources.
- Acts 13:18 etropophoresin vs. etrophoesen: a textual variant with different
  LXX Deut 1:31 readings — noted in context.
- Acts 13:47 Isa 49:6 application: the Servant Song applied to Paul/Barnabas,
  not to Jesus — a bold appropriation of prophetic identity.
- Acts 13:48 tetagmenoi: 'enrolled/appointed' for eternal life — Hellenistic
  administrative vocabulary for civic enrollment, giving the statement a
  political resonance as well as a predestinarian theological one.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS = {
  "12": {
    "1": "<p><strong>Hērōdēs ho basileus</strong> ('Herod the king'): Herod Agrippa I (10 BC–AD 44), grandson of Herod the Great and nephew of Herod Antipas (who executed John the Baptist). Raised in Rome as a companion of the imperial household — educated alongside the future emperors Caligula and Claudius — his social connections allowed him to acquire territorial titles piecemeal: Philip's tetrarchy (AD 37), Antipas's Galilee (AD 39), and finally Judea and Samaria from Claudius (AD 41), the first ruler since Herod the Great to control all Jewish territory. Josephus (<em>Ant.</em> 19.7-8) portrays him as popular with the Jewish people, scrupulous in Torah observance when in Jerusalem, and politically astute — the most credible Herod in Jewish memory.</p>",

    "2": "<p><strong>Iakōbon ton adelphon Iōannou anheilen machairē</strong> ('he killed James the brother of John with the sword'): the first apostolic martyrdom in Acts. James and John, sons of Zebedee, had asked for the seats at Jesus's left and right in his glory (Mark 10:35-40); Jesus had responded with the cup-of-suffering prophecy. The sword execution — probably beheading — was within Herod's authority as a Jewish king for sedition. That James was executed first among the Twelve and Luke reports it in a single clause without theological elaboration is historically honest: no explanation is offered, no miracle rescues him. The contrast with Peter's miraculous escape heightens both the unexpectedness of the rescue and the reality of martyrdom in the same narrative.</p>",

    "3": "<p><strong>Heorakas tōn azymōn</strong> ('Festival of Unleavened Bread'): the seven-day festival immediately following Passover (Lev 23:5-8). Jerusalem's population swelled multiple times over with pilgrims during this period; any public execution or trial would have maximum visibility. Herod's arrest of Peter during the festival — with a public trial planned afterward — suggests a calculated political spectacle timed to the religious calendar, the same strategy the Sanhedrin had used when plotting against Jesus (Mark 14:2, 'not during the feast'). The Passover/Unleavened Bread context also invites the Exodus typology that Luke develops through the angelic rescue of vv.6-11.</p>",

    "4": "<p><strong>Tetradioisi tōn stratiōtōn tessarsin</strong> ('four squads of four soldiers each'): a <em>quaternio</em> was the standard Roman guard unit of four soldiers, rotating through four six-hour watches. Sixteen soldiers total for one prisoner was exceptional security — reflecting either Herod's determination not to lose another apostle or his knowledge of the earlier miraculous prison release (5:19-20). The explicit plan — 'public trial after Passover' (<em>meta to pascha</em>) — shows Herod respecting the festival's solemnity while planning a theatrical execution to follow it, using the holy season as stage-setting for political theater.</p>",

    "5": "<p><strong>Ektenōs ginomenē hypo tēs ekklēsias</strong> ('earnestly/fervently being made by the church'): the adverb <em>ektenōs</em> (stretched out, fervent) appears in Luke 22:44 for Jesus's prayer in Gethsemane ('praying more earnestly'). The verbal echo is available: Peter imprisoned during Passover, the church praying earnestly — as Jesus prayed before his Passover arrest. The prayer is 'to God' (<em>pros ton theon</em>) — specific directed petitionary prayer, not general spiritual posture. The structural contrast Luke creates: Roman military power (four squads, iron gate, v.4, v.10) versus the church's prayer (v.5) — with the outcome demonstrating which is more powerful.</p>",

    "6": "<p><strong>Desmios halysesin dysin</strong> ('bound with two chains'): Roman <em>custodia militaris</em> — chained at each wrist to a soldier on either side. Peter sleeping (<em>koimōmenos</em>) the night before his trial echoes both Jesus sleeping in the boat during the storm (Mark 4:38 — trust in God amid danger) and the disciples sleeping in Gethsemane (Mark 14:37-41 — the contrasting failure). Peter's sleep signals Lukan theology of apostolic confidence: the man scheduled for execution tomorrow morning sleeps soundly. The imprisonment during Passover, the unjust condemnation, the imminent death — all frame Peter's situation as a Passion pattern which divine rescue will interrupt.</p>",

    "7": "<p><strong>Epataxen de tēn pleuran tou Petrou</strong> ('struck him on the side'): the angel wakes Peter physically — a prod on the side, not a symbolic gesture. The light (<em>phōs</em>) flooding the cell recalls the divine glory of theophany throughout Acts and the OT (Ezek 1:4; Isa 60:1). The chains 'fell off' (<em>exepesan</em>) — no struggle, no keys, no human intervention. The passive construction emphasizes divine agency. The same verb is used for Paul's chains in Acts 16:26. Notably, the same verb <em>epataxen</em> (struck) will describe the angel's action against Herod in v.23 — the word that rescues the apostle kills the persecutor.</p>",

    "8": "<p><strong>Zōsai kai hupodēsai ta sandalia</strong> ('fasten your belt and put on your sandals'): the practical dress-sequence mirrors a traveler preparing for immediate departure. The specificity — clothes, sandals, cloak — is a realism marker: visions in Acts tend toward symbolic imagery; this scene has the textures of reported experience. The command sequence recalls the Passover preparation instruction in Exod 12:11 ('eat it with your cloak tucked in, your sandals on your feet and your staff in your hand'). The Exodus echo is available: just as Israel dressed to leave Egypt at God's command, Peter dresses to leave Herod's prison at the angel's command.</p>",

    "9": "<p><strong>Edokei de horama blepein</strong> ('he thought he was seeing a vision'): the confusion between vision and reality recurs in Acts (Ananias in 9:10; Cornelius in 10:3; Peter in 10:10-16). The disorientation confirms that this experience exceeds ordinary expectation; Peter cannot immediately categorize what is happening. The narrative allows the reader to know what Peter does not: the rescue is real. The retrospective recognition in v.11 ('now I know without a doubt') parallels the Emmaus road disciples (Luke 24:31-35) — recognition comes after the event, not during it.</p>",

    "10": "<p><strong>Automate hē pylinē ēnoigē autois</strong> ('the iron gate opened automatically'): <em>automatos</em> ('of its own accord,' without visible human agency) is the term for miraculous openings in Greek literature and in Acts 5:19 (the earlier prison release). The iron gate (<em>pylinē sidēra</em>) was the outer security gate — the final barrier. Its self-opening marks the end of Roman jurisdiction over Peter. 'The length of one street' grounds the story geographically before the angel departs, leaving Peter to navigate by himself. The transition from miraculous assistance to ordinary human navigation is characteristic of Luke's rescue narratives — the divine acts in ways that leave human agency intact.</p>",

    "11": "<p><strong>En heautō genomenos</strong> ('coming to himself'): the idiom for the return of full self-awareness after disorientation — the same phrase used for the prodigal son's moment of clarity in Luke 15:17. <em>Nun oida alēthōs</em> ('now I know truly'): the transition from confused participant to theological interpreter. Peter's interpretation — 'the Lord has sent his angel and rescued me from Herod's clutches' — connects the rescue to the pattern of angelic rescue throughout Israel's history (Dan 3:28; 6:22; Ps 34:7). The phrase 'everything the Jewish people were hoping would happen' shows Peter's awareness of the coordinated opposition between Herod and the Jerusalem leadership.</p>",

    "12": "<p><strong>Oikian Marias tēs mētros Iōannou tou epikaloumenou Markou</strong> ('the house of Mary the mother of John called Mark'): the house was large enough for a significant gathering and wealthy enough to have a servant named Rhoda — a prosperous Jerusalem household. John Mark (companion of Paul and Barnabas, and per 1 Pet 5:13 Peter's interpreter and associate) is introduced through his mother — grounding the later narrative in a specific household's history. The gathering for prayer (v.5) was apparently in Mary's house; the community assembled there knew it as a prayer gathering point. The reader now knows where the praying community of v.5 was located — and that the prayer is answered to the very house where prayer was being made.</p>",

    "13": "<p><strong>Paidiskē onomati Rhodē</strong> ('a servant girl named Rhoda'): Rhoda (meaning 'rose') is the only named servant in Acts and one of the few named women who is not a major theological figure. The scene she initiates (vv.13-16) is one of Acts' few comic interludes — a recognizable human moment of excitement overriding good sense. Servant girls in ancient Mediterranean households were typically enslaved; Rhoda's central role in the narrative and the detail of her name suggests she was known to the community for whom Luke wrote. Her function in the narrative is to be the first to recognize the answered prayer — before any of the praying congregation does.</p>",

    "14": "<p><strong>Apo tēs charas ouk ēnoixen tēn pylōna</strong> ('from joy she did not open the gate'): the irony is deliberate — joy at recognizing Peter's voice prevents the obvious response of letting him in. <em>Chara</em> (joy) is Luke's consistent word for the community's response to God's saving acts (Luke 1:14; 2:10; 10:17; 15:7, 10, 32; Acts 8:8; 13:52; 15:3). The structural irony reverses the prison scenario: Peter was inside a locked space and got out; now he is outside a locked space and cannot get in. The gate that should open for the rescued prisoner remains shut while Rhoda runs to announce the news.</p>",

    "15": "<p><strong>Ho angelos estin autou</strong> ('it must be his angel'): the belief in personal guardian angels — that prominent figures (and perhaps all righteous individuals) had angelic counterparts — was attested in Jewish tradition (Exod 23:20; Dan 10:13; Matt 18:10, 'their angels in heaven always see the face of my Father'). The community's assumption is that Peter has been executed (while they prayed for his release) and his angel-double has come to announce the death. Their 'faith' in the resurrection of the dead (which they affirm theologically) does not extend to believing the servant girl's report that the living Peter is at the gate — a pattern Luke uses throughout: the resurrection and miraculous deliverance always exceed the expectation of those who believe in them abstractly.</p>",

    "16": "<p><strong>Epeimenen krouōn</strong> ('he kept on knocking'): the imperfect shows persistent action — Peter knocked continuously while the community debated. Their astonishment (<em>exestēsan</em>) when they finally opened the door is the same word used for the crowds at Pentecost (2:7) and other miraculous events in Acts. Luke's theological point is pointed: the church was praying earnestly for Peter's release, and when the answer to that prayer knocks on their door, they are astonished. Answered prayer, in Luke's narrative, consistently exceeds the faith of those who prayed.</p>",

    "17": "<p><strong>Eipate Iakōbō kai tois adelphois</strong> ('tell James and the brothers'): Peter's instruction to report to James — not to the Twelve — marks the formal transition of Jerusalem church leadership. James the Lord's brother (Gal 1:19; 2:9, 12) will be the Jerusalem leader from this point forward (Acts 15:13; 21:18). Peter's departure 'to another place' (<em>eis heteron topon</em>) is deliberately vague — Luke either did not know the destination, declined to name it to protect Peter, or both. Tradition connects this with Rome; whatever the destination, it marks Peter's exit from the Jerusalem narrative and the beginning of James's central role.</p>",

    "18": "<p><strong>Tarachos ouk oligos</strong> ('no small commotion'): Lukan litotes — 'not small' = very great. Roman law required that guards who permitted a prisoner to escape were liable to the prisoner's sentence — if the prisoner faced execution, so did the guards. This legal consequence explains the commotion: sixteen soldiers face the death penalty for Peter's absence. The commotion is Luke's realistic counterpoint to the miraculous rescue — the world responds to Peter's absence with appropriate institutional panic, even as Peter is safely housed at Mary's home.</p>",

    "19": "<p><strong>Anakrinas tous phylakas ekeleusen apachthēnai</strong> ('cross-examined the guards and ordered them led away'): the judicial term <em>anakrinō</em> (examine, interrogate) is the same word Paul uses in 1 Cor 4:3 for self-examination before God. The guards' execution is narrated in a subordinate clause without editorial comment — Luke records Roman military justice neutrally, as he records Roman administrative decisions throughout Acts. Herod's move to Caesarea closes the Jerusalem episode; Caesarea was the Roman administrative capital and Herod's preferred residence, offering easier access to Mediterranean communications.</p>",

    "20": "<p><strong>Thymomachōn Tyrioisi kai Sidōnioisi</strong> ('bitterly angry with the people of Tyre and Sidon'): Tyre and Sidon were commercial rather than agricultural centers — dependent on the grain of the Galilean and Judean interior. 'Food supply from the royal territory' (<em>trephesthai apo tēs basililikēs chōras</em>) reflects the agricultural geography: the Phoenician coast fed on the hinterland. Securing Blastus's support (<em>peisantes Blaston</em>) was the standard patronage mechanism for gaining royal access — the king's personal household staff controlled access to the king's person. The political dispute and its commercial stakes set the stage for the theatrical public address of v.21.</p>",

    "21": "<p><strong>Basilikēn esthēta endysas</strong> ('wearing his royal robes'): Josephus (<em>Ant.</em> 19.8.2) describes the same event: at dawn on the second day of games at Caesarea held in honor of the emperor, Herod appeared wearing a robe made entirely of silver, which caught the early morning sun and dazzled the crowd. Luke's 'royal robes' and Josephus's silver robe describe the same theatrical spectacle. The corroboration between Acts and Josephus at this point — independent sources giving the same event with consistent details — is one of the strongest external confirmations of Acts' historical reliability.</p>",

    "22": "<p><strong>Theou phōnē kai ouk anthrōpou</strong> ('voice of a god, not of a mortal'): the divine acclamation of living rulers was standard in Hellenistic ruler-cult practice. In the Greek East crowds regularly addressed rulers as divine — especially those connected to the imperial household. The Herodians generally avoided accepting divine titles in Jewish contexts while exploiting them in Hellenistic ones. The crowd's shout is comprehensible in its Caesarean Greco-Roman context; the problem is not their pagan enthusiasm but Herod's failure to deflect it to God (v.23, 'he did not give praise to God'). The same God who heard the church's prayer (v.5) and sent the rescuing angel now sends the judging one.</p>",

    "23": "<p><strong>Exairetōs hypo angelou kyriou ... egeneto skōlēkobrōtos</strong> ('struck down by an angel of the Lord ... eaten by worms'): Josephus (<em>Ant.</em> 19.8.2) records Agrippa's sudden illness at the same Caesarean games, describing him looking up and seeing an owl perched on a rope (an omen of death), then suffering violent abdominal pain and dying five days later, attributing it to divine punishment for accepting divine honor. Luke and Josephus agree on: the Caesarean games, the theatrical setting, the sudden illness, and divine causation. The 'eaten by worms' (<em>skōlēkobrōtos</em>) matches the description of Antiochus Epiphanes's death in 2 Macc 9:5-9 — a deliberate literary parallel: both persecutors of God's people die under divine judgment by the same gruesome means.</p>",

    "24": "<p><strong>Ho de logos tou theou ēuxanen kai eplēthyneto</strong> ('the word of God continued to grow and multiply'): the sixth of Luke's growth summaries in Acts (2:41, 47; 4:4; 5:14; 6:7; 9:31), each following opposition. The vocabulary — <em>auxanō</em> (grow) and <em>plēthynō</em> (multiply) — echoes Gen 1:28 (creation mandate: 'be fruitful and multiply') and Exod 1:7 LXX (Israel's growth in Egypt: 'increased greatly and multiplied'). The irony is pointed: in the same narrative unit where the king who tried to stop the Word dies by divine judgment, the Word does exactly what Pharaoh's Egypt could not stop — it multiplies. The growth summary closes the Agrippa episode and reopens the mission narrative.</p>",

    "25": "<p><strong>Iōannēn ton epikaloumenon Markon</strong> ('John called Mark'): John Mark's introduction as companion prepares for the first missionary journey (13:5) and his later departure (13:13), which will cause conflict between Paul and Barnabas (15:36-41). Luke introduces Mark neutrally here — as he introduced Saul at Stephen's stoning (7:58) — as a minor character whose significance will emerge. The parallel is available: Saul watched Stephen's death approvingly; John Mark will depart at a critical moment. Both introductions are understated; both characters will be central to the narrative's next phases. <em>Plērōsantes tēn diakonian</em>: the famine-relief mission (11:27-30) is complete; the first missionary journey begins.</p>"
  },

  "13": {
    "2": "<p><strong>Leitourgountōn de autōn tō kyriō kai nēsteuontōn</strong> ('while they were worshipping the Lord and fasting'): <em>leitourgousin</em> is the LXX and NT word for priestly/cultic service (from which 'liturgy' derives). The Spirit's commission comes during communal worship and fasting — not a planning meeting or individual vision. The corporate practice of spiritual discernment through fasting was a recognized Jewish practice (Esth 4:16; Neh 1:4; Dan 9:3). The Spirit speaks through the gathered worshipping community; the corporate response of v.3 confirms it. The Antioch church commissions its two best leaders — giving up its own resources for the mission.</p>",

    "3": "<p><strong>Epithentas tas cheiras autois apelisan</strong> ('placing their hands on them, they sent them away'): laying on of hands for commissioning was a Jewish practice (Num 27:18-23, Moses commissioning Joshua; Acts 6:6, commissioning the deacons) adopted and developed by the early church. The gesture transferred authority, blessing, and (in some contexts) Spirit-empowerment. The additional fasting and prayer before the laying on of hands is the full commissioning sequence: community discernment → prayer → fasting → laying on of hands → release. The community freely sends its most gifted leaders — a countercultural generosity for any institution, ancient or modern.</p>",

    "4": "<p><strong>Apelthontes eis Seleukian</strong> ('they went down to Seleucia'): Seleucia Pieria was Antioch's port city, about 16 miles away on the Mediterranean — the natural embarkation point for Cyprus. The explicit phrase 'sent on their way by the Holy Spirit' (<em>ekpemphthentes hypo tou hagiou pneumatos</em>) reframes the geography: both the community and the Spirit send them. Cyprus was Barnabas's homeland (4:36, 'a Levite from Cyprus'). Beginning on familiar territory — where Barnabas had family, social connections, and knowledge of the Jewish community — reflects practical missionary wisdom alongside Spirit-direction.</p>",

    "5": "<p><strong>En tais synagōgais tōn Ioudaiōn</strong> ('in the Jewish synagogues'): the 'to the Jew first' pattern (Rom 1:16) — synagogue preaching as the entry point — characterizes Paul's missionary strategy throughout Acts (13:5, 14; 14:1; 17:1-2, 10, 17; 18:4; 19:8). The synagogue was not merely a religious building; it was the center of Jewish communal life — where Torah was read, disputes adjudicated, charity organized. Beginning there gave the apostolic message its Hebrew-Bible context, its theological vocabulary, and an audience familiar with the prophetic texts the message claimed were fulfilled. Salamis was the main port of eastern Cyprus, likely having a substantial Jewish community.</p>",

    "6": "<p><strong>Magos pseudoprophētēs Ioudaios</strong> ('a Jewish sorcerer and false prophet'): <em>magos</em> (magician/sorcerer) originally meant Persian priestly functionaries; it had come to mean anyone practicing divination, magic, or astrology for hire. Jewish names were frequently used in magical papyri because of the reputation of Jewish divine names for efficacy. Bar-Jesus = 'son of Jesus/Joshua' — an Aramaic patronymic. That he was attached to the proconsul's household reflects the ancient patronage relationship: diviners and magicians served elite clients as personal advisors. Paphos was the western end of Cyprus and the Roman administrative center — the seat of the proconsul.</p>",

    "7": "<p><strong>Sergiō Paulō anthupatō</strong> ('the proconsul Sergius Paulus'): Cyprus was a senatorial province, governed by a proconsul (<em>anthupatos</em>) appointed by the Roman Senate. Sergius Paulus is attested in epigraphy: inscriptions from Cyprus and from Rome and Pisidian Antioch show his family's connections. The Pisidian Antioch family connection may explain why that city was Paul's next destination after Cyprus (13:14). <em>Andri synetō</em> ('an intelligent man'): Luke's neutral-positive characterization sets up the genuine response of v.12. Roman officials of senatorial rank often had genuine philosophical and religious interests; access to Josephus and other Jewish intellectuals was common in elite Roman circles.</p>",

    "8": "<p><strong>Anthistato autois ho Elymas ho magos</strong> ('Elymas the sorcerer opposed them'): the parenthetical note — 'for that is what his name means' — suggests <em>Elymas</em> is a transcription of an Aramaic or Arabic word for 'wise man' or 'powerful one.' Various etymologies are proposed; none is certain. Bar-Jesus's dual identity (Jewish patronymic + professional Greek title) shows him operating in both Jewish and Hellenistic registers — the same cultural code-switching as Paul himself, though to opposite ends. His opposition to Paul and Barnabas is self-interested: if the proconsul converts, the sorcerer loses his patron and livelihood.</p>",

    "9": "<p><strong>Saulos de ho kai Paulos</strong> ('Saul, also called Paul'): the name transition happens at precisely the first engagement with a Roman official in a Roman administrative center — the bilingual Jewish-Roman man operating in a Roman context shifts to his Roman name. Many Diaspora Jews used a Hebrew/Aramaic name within the community and a Greco-Roman name in the wider world; the names were not necessarily related etymologically. Saul/Saulos was his Jewish name (from the tribe of Benjamin, after King Saul, Phil 3:5); Paulus was his Roman <em>cognomen</em>. From this point Luke uses 'Paul' consistently — signaling the shift in narrative focus toward the Gentile mission world.</p>",

    "10": "<p><strong>Huie diabolou, echthre pasēs dikaiosynēs</strong> ('son of the devil, enemy of all righteousness'): Paul's rebuke follows the pattern of OT prophetic invective (Ezek 13:10-16 against false prophets; Isa 5:20 against those calling evil good). 'Son of the devil' (<em>huios diabolou</em>) contrasts with Bar-Jesus's name ('son of Jesus/Joshua') — pointed irony. 'Perverting the right ways of the Lord' (<em>diastrephōn tas hodous kyriou tas eutheias</em>) echoes Hos 14:9 LXX and connects the rebuke to the 'Way' vocabulary used for the Christian movement throughout Acts. The sorcerer who distorts the Way is the antithesis of the movement's own identity.</p>",

    "11": "<p><strong>Cheiragōgon zētōn</strong> ('groping, seeking someone to lead him by the hand'): the punishment — temporary blindness — echoes Paul's own blinding on the Damascus road (9:8-9). Paul, who was blinded when opposing the truth (9:1-4) and led by the hand into Damascus (9:8), now pronounces temporary blindness on one opposing the truth and groping for a hand to lead him. The symmetry is deliberate — Luke uses Paul's past as the template for his prophetic action. 'Mist and darkness' (<em>achlys kai skotos</em>) are used in the LXX for spiritual blindness (Isa 60:2; Ps 88:6 LXX). The blinding is temporary — 'for a time' (<em>achri kairou</em>) — leaving open the possibility of repentance.</p>",

    "12": "<p><strong>Episteusen ekplēssomenos epi tē didachē tou kyriou</strong> ('he believed, being amazed at the teaching about the Lord'): the first recorded conversion of a Roman official of senatorial rank. What produced faith was the <em>didachē</em> (teaching) — the content of the apostolic message — not the miracle alone. Luke consistently connects miracles to teaching in Acts; miracles create openness, but the content produces faith. The 'teaching about the Lord' marks the proconsul's conversion as genuine doctrinal conviction, not merely wonder at a power-display — the same distinction Luke makes throughout the healing and miracle narratives of Acts.</p>",

    "13": "<p><strong>Iōannēs de apochōrēsas autōn hypestrepsen eis Hierousalēm</strong> ('John departed and returned to Jerusalem'): Luke narrates Mark's departure without explanation or comment — a historian's restraint. Paul's later sharp refusal to take Mark on the second journey (15:38, calling it 'desertion') indicates the abandonment was significant. Ancient and modern interpreters speculate about reasons: homesickness, the rigor of the upcoming Taurus mountain crossing, theological disagreement about the Gentile mission, concern about the shifting leadership from Barnabas to Paul. Perga was the natural disembarkation point on the Pamphylian coast; continuing required commitment to the difficult inland journey. Luke records the crack without adjudicating it.</p>",

    "14": "<p><strong>Eis Antiocheian tēn Pisidian</strong> ('to Pisidian Antioch'): a Roman colony in the province of Galatia (or Phrygia-Galatica), about 100 miles inland from Perga across the Taurus mountain range — a significant and dangerous journey. Paul's reference in 2 Cor 11:26 to 'danger from rivers, danger from bandits' may reflect this route. Founded by Seleucus I and refounded as a Roman colony under Augustus, Pisidian Antioch was a strategically important military and administrative center. The Sergius Paulus family inscription from this city — the same proconsul Paul had just converted — may indicate he gave Paul a letter of introduction to his family connections there.</p>",

    "15": "<p><strong>Meta tēn anagnōsin tou nomou kai tōn prophētōn</strong> ('after the reading from the Law and the Prophets'): the synagogue liturgy included prescribed Torah sections (<em>parashahs</em>) and associated prophetic readings (<em>haphtarahs</em>), followed by teaching/homily by any qualified male. The invitation — 'if you have a word of encouragement (<em>logos paraklēseōs</em>) for the people' — reflects the openness of ancient synagogue practice to visiting teachers. The word <em>paraklēsis</em> (encouragement, consolation, exhortation) echoes Isa 40:1 ('Comfort, comfort my people') — positioning Paul's speech as the consolation Israel had been awaiting.</p>",

    "16": "<p><strong>Anastas de Paulos kai kataseisas tē cheiri</strong> ('Paul stood and motioned with his hand'): standing was the orator's position in Hellenistic rhetoric; the hand gesture silenced the crowd for attention — a standard rhetorical opening in Jewish and Greco-Roman contexts. Paul's opening address — 'Fellow Israelites and God-fearers who worship God' — includes both ethnic Jews and Gentile God-fearers (Greek-speaking pagans attracted to Judaism who attended synagogue without full conversion). God-fearers were a significant Diaspora phenomenon; they would become a primary audience for the Pauline mission (13:43, 50; 17:4, 17; 18:7).</p>",

    "17": "<p><strong>Ho theos tou laou toutou Israel exelexato tous pateras hēmōn</strong> ('the God of this people Israel chose our ancestors'): Paul's speech begins with election — God's initiative — which is the foundation of Israel's entire narrative. The structure parallels Stephen's speech (ch7): OT history from Abraham → exodus → wilderness → conquest → judges → kings → David → Jesus. But where Stephen's survey built to accusation, Paul's builds to proclamation. Each stage is God's action — 'he chose,' 'he led them out,' 'he endured,' 'he overthrew,' 'he gave' — establishing the pattern of divine initiative that the resurrection continues and completes.</p>",

    "18": "<p><strong>Etropophoresin autous</strong> ('he endured/bore with/cared for them'): a textual variant between <em>etropophoresin</em> (he endured/put up with them, from Num 14:34's patience under provocation) and <em>etrophoesen</em> (he nourished/cared for them, from Deut 1:31 LXX: 'the LORD your God bore you as a father carries his son'). The latter has strong manuscript support and gives a more tender image of God as nursing parent carrying a child through the wilderness. Both readings are theologically rich; if the original is <em>etrophoesen</em>, the forty wilderness years are an act of divine parenthood rather than divine patience.</p>",

    "19": "<p><strong>Kathēlōsen hepta ethnē</strong> ('he defeated/destroyed seven nations'): the seven Canaanite nations of Deut 7:1 — Hittites, Girgashites, Amorites, Canaanites, Perizzites, Hivites, Jebusites. Their displacement through Joshua 6-12 is compressed into one clause. The inheritance language (<em>kataklēronomēsen</em>, 'gave as inheritance') continues the Deuteronomic vocabulary of land-as-gift: Canaan was always gift, not conquest by right, requiring continued faithfulness from the recipients. The inclusion of the conquest in Paul's historical survey is unusual for Paul's letters but appropriate for a synagogue audience whose entire identity was rooted in the land-promise.</p>",

    "20": "<p><strong>Hōs etesi tetrakosioisi kai pentēkonta</strong> ('about 450 years'): the chronological calculation is debated. The 450 years may count: the sojourn (400 years, Gen 15:13) + wilderness (40 years) + Joshua's conquest (10 years) = 450; or it follows a different calculation using 1 Kgs 6:1. The 'about' (<em>hōs</em>) acknowledges approximation; Luke follows a standard Jewish chronological tradition. The Judges period and Samuel mark the transition to monarchy — the narrative pivot toward David. Samuel functions as the last judge and the kingmaker whose anointing of David gives theological legitimacy to the Davidic line.</p>",

    "21": "<p><strong>Ētēsanto basilea kai edōken autois ho theos ton Saoul</strong> ('they asked for a king and God gave them Saul'): the emphasis is on Israel's initiative — they 'asked' for a king (1 Sam 8:5-6); God accommodated their request while warning of its consequences (1 Sam 8:10-18). The 40-year reign is not stated in the MT; Acts 13:21 and Josephus (<em>Ant.</em> 6.14.9) give 40 years, following a traditional round number. The brevity of the Saul section — one verse — mirrors the prophetic tradition that viewed Saul's reign as a failed detour; the emphasis falls entirely on God's removal of Saul and elevation of David.</p>",

    "22": "<p><strong>Kata tēn kardian mou</strong> ('according to my heart'): the composite citation blends 1 Sam 13:14 ('a man after his own heart') and Ps 89:20 LXX ('I have found David'). Neither OT passage uses the exact wording of Acts 13:22; the blending reflects synagogue practice of thematic citation (<em>gezerah shavah</em> — combining texts with shared vocabulary or theme). David as 'man after God's own heart' is the theological baseline: if David embodied God's purposes, his descendant who fulfills David's hopes represents the culmination of that divine-human alignment.</p>",

    "23": "<p><strong>Apo tou spermatos touton ēgagen ho theos tō Israēl sōtēra Iēsoun</strong> ('from this man's descendants God has brought to Israel the Saviour Jesus'): the title <em>sōtēr</em> (Saviour) is applied to Jesus only here in Acts (though <em>sōtēria</em>/salvation recurs). In the Hellenistic world, <em>sōtēr</em> was a title for deified rulers — Ptolemy I was 'Soter,' Augustus was acclaimed Soter throughout the Greek East. In a Roman colony with an imperial cult, Paul's use of the term is a counter-proclamation: the Saviour is not Caesar or his successors but Jesus of David's line, raised by the God of Israel.</p>",

    "24": "<p><strong>Prokēryxantos Iōannou baptisma metanoias</strong> ('John preached repentance and baptism'): John the Baptist's role as precursor is explained to an audience that may not know his story. The phrase <em>pro prosōpou</em> ('before the face') echoes Mal 3:1 LXX ('I will send my messenger before my face') — cited in Luke's Gospel (Luke 7:27) as the scriptural warrant for John's role. Even in a brief summary, Paul's speech invokes the prophetic frame that Luke's Gospel established for the Baptist, demonstrating that the same interpretive tradition governed both Peter's and Paul's preaching.</p>",

    "25": "<p><strong>Trechontos de Iōannou ton dromon</strong> ('as John was completing his course'): the athletic metaphor <em>dromos</em> (race, course) for a life of ministry is Greek vocabulary common in Paul's letters (1 Cor 9:24-27; Phil 3:14; 2 Tim 4:7). John's self-distancing — 'I am not the one you think I am... after me comes one whose sandals I am not worthy to untie' — echoes all four Gospels' Baptist tradition. Untying sandals was the task of the lowest slave; John places himself below even that rank relative to Jesus. The consistent Baptist tradition across all the apostolic speeches confirms the stability of the core kerygmatic summary.</p>",

    "26": "<p><strong>Hyioi genous Abraam kai hoi phoboumenoi ton theon</strong> ('sons of the family of Abraham and those who fear God'): the second direct address to the dual synagogue audience. 'This message of salvation has been sent' (<em>exapestalē</em>) — the passive marks divine sending, not merely apostolic initiative. Both ethnic Jews and God-fearers are equally addressed as recipients of the same salvation — a programmatic statement that the synagogue context makes bold. The 'to the Jew first' principle (v.46) does not mean exclusive priority; it means sequence, after which the Gentiles are equally included.</p>",

    "27": "<p><strong>Touto agnoesan</strong> ('this they did not recognize/know'): the 'ignorance' motif recurs in apostolic preaching in Acts (3:17; 17:30) as an explanation for the crucifixion that is simultaneously explanatory and accusatory — the ignorance is culpable, not exculpatory. 'The words of the prophets that are read every Sabbath' — the irony: texts that predicted the Messiah's suffering were heard weekly but not recognized as fulfilled. The Deuteronomistic pattern of Israel rejecting God's messengers (Stephen's theme in ch7) is here applied specifically to the condemnation of Jesus by Jerusalem's leaders.</p>",

    "28": "<p><strong>Mēdemian aitian thanatou heurontes</strong> ('having found no cause for a death sentence'): the innocence declaration is a consistent element of apostolic preaching (Peter in 2:23; 3:13-15). Paul uses <em>aitia</em> (legal cause, charge) — the same term in Jesus's trial (Luke 23:4, 14, 22, 'I find no basis for a charge against him'). The request to Pilate places the death within Roman legal framework while attributing moral causation to the Jerusalem leadership — the combination that Paul's audience, familiar with Roman legal procedure, would understand immediately.</p>",

    "29": "<p><strong>Kathelontes apo tou xylou</strong> ('taking him down from the tree'): the cross is consistently identified as a 'tree' (<em>xylon</em>) in the earliest Petrine/Pauline tradition — Acts 5:30; 10:39; 13:29; Gal 3:13. The vocabulary invokes Deut 21:22-23 ('anyone hung on a tree is under God's curse') and its Pauline development in Gal 3:13 ('Christ redeemed us from the curse of the law by becoming a curse for us'). The tree/cross identification was not incidental but the deliberate theological framing of the crucifixion as the bearer of covenant curse — the death that absorbs judgment on behalf of the covenant people.</p>",

    "30": "<p><strong>Ho de theos ēgeiren auton ek nekrōn</strong> ('but God raised him from the dead'): the adversative <em>de</em> carries the gospel's full weight. The entire speech has been building to this reversal: the same divine initiative that led Israel out of Egypt, overthrew seven nations, raised up David, and endured forty years of wilderness rebellion — that God, with the same pattern of overturning human action, raised Jesus. 'God raised him' (<em>ēgeiren</em>) in exactly this formulation is the earliest Pauline credal statement (1 Thess 1:10; 1 Cor 15:4; Rom 10:9).</p>",

    "31": "<p><strong>Hōphthē epi hēmeras pleious tois synanabasi autō apo tēs Galilaias</strong> ('he was seen for many days by those who had traveled with him from Galilee'): Paul distinguishes his testimony from theirs — they are eyewitnesses of the resurrection appearances (<em>martyres autou</em>); Paul's encounter came later (1 Cor 15:8, 'last of all, as to one untimely born'). By naming the Galilean disciples as 'now his witnesses to our people' (present tense), Paul grounds the resurrection claim in identifiable living witnesses — not ancient tradition but current testimony accessible to investigation.</p>",

    "32": "<p><strong>Kai hēmeis hymas euangelizometha</strong> ('we proclaim to you the good news'): <em>euangelizō</em> (proclaim good news) is Paul's core missionary verb. Its object is 'what God promised our ancestors' — the content of the good news is the fulfillment of Israel's ancient promises. Paul positions himself not as the innovator of a new religion but as the fulfiller of Israel's hope. The continuity with Israel's Scripture — the entire survey of vv.17-31 — grounds the proclamation in the authoritative narrative the synagogue audience already accepts as true.</p>",

    "33": "<p><strong>Psalm 2:7</strong>: 'You are my son; today I have become your father' — cited as fulfilled in the resurrection, not the baptism or transfiguration. The 'today' of the divine begetting is the resurrection day; Paul follows the same interpretation as Heb 1:5 and 5:5. Psalm 2 was a royal enthronement psalm in its original context — the king's formal adoption as God's 'son' at coronation. Applied to the resurrection, it becomes the enthronement of the risen king: the resurrection is Jesus's coronation as the Davidic king who fulfills Psalm 2's vision of universal dominion.</p>",

    "34": "<p><strong>Isa 55:3 LXX</strong>: 'I will give you the holy and sure blessings of David' — the <em>ta hosia Dauid ta pista</em> ('holy and sure blessings') promised to David. The Isaianic promise extends the Davidic covenant universally ('come to me, all you who are thirsty'); the covenant mercies of David are not limited to ethnic Israel. The resurrection fulfills these covenant promises: the one who rose did not see decay, enabling the 'sure' (unbreakable) covenant blessings to flow through him. The connection between resurrection and Davidic covenant is Paul's distinctive contribution to the chain of OT citations.</p>",

    "35": "<p><strong>Psalm 16:10 LXX</strong>: 'You will not let your holy one see decay' — already cited by Peter at Pentecost (Acts 2:27-28) with the identical application. The shared exegetical tradition between Peter and Paul confirms a common apostolic interpretive practice: David died and decayed; therefore the Psalm's 'holy one' (<em>hosion</em>) must refer to a greater David who would not. The same psalm, the same argument, two different apostles in two different cities — demonstrating that the Psalm 16 resurrection argument was not Paul's innovation but a shared early Christian tradition.</p>",

    "36": "<p><strong>Hyperētēsas tē tou theou boulē ekoēmēthē</strong> ('having served God's purpose in his own generation, he fell asleep'): 'in his own generation' (<em>tē idiai genea</em>) is the interpretive key — David fulfilled his appointed purpose within the limits of his era. He served his generation, then died. <em>Ekoēmēthē</em> ('fell asleep'): the euphemism for death common in Judaism and Christianity, used throughout Paul's letters (1 Cor 7:39; 11:30; 15:6, 18, 20, 51; 1 Thess 4:13-15). The burial and decay of David's body is a historical fact that removes David from consideration as the Psalm's ultimate referent.</p>",

    "37": "<p><strong>Hon de ho theos ēgeiren ouk eiden diaphthoran</strong> ('but the one God raised did not see decay'): the logical conclusion of the Psalm 16 argument. The resurrection happened before decomposition — 'the third day' tradition (1 Cor 15:4) specifies that the resurrection preceded decay. Paul's argument depends on the resurrection being a bodily event: a merely spiritual resurrection would not address the 'seeing decay' point. The physical resurrection of the body is not incidental to the argument but the specific claim on which the entire Psalm 16 application depends.</p>",

    "38": "<p><strong>Aphesis hamartiōn katangelletai hymin</strong> ('forgiveness of sins is proclaimed to you'): <em>aphesis</em> (forgiveness/release) carries the Jubilee connotation — release from debt, obligation, accumulated covenant failure. This is what the Day of Atonement rituals pointed toward and could not permanently achieve (Heb 10:1-4). Paul's sermon offers what the entire sacrificial system aimed at but could not deliver: actual and final forgiveness grounded in the resurrection of the sin-bearer. The proclamation is performative — 'is proclaimed' (<em>katangelletai</em>) in the present tense: the announcement itself makes the forgiveness available.</p>",

    "39": "<p><strong>Apo pantōn hōn ouk ēdynēthēte en nomō Mōyseōs dikaiōthēnai, en toutō pas ho pisteuōn dikaioutai</strong> ('from everything the law of Moses could not justify you from, in this one everyone who believes is justified'): the most theologically concentrated statement in Acts. The law of Moses could not justify — not because it was wrong but because it was not designed to justify from the record of accumulated transgression (cf. Rom 8:3, 'what the law was powerless to do'). 'Justified' (<em>dikaioutai</em>) is Paul's legal term for being declared righteous before God's judgment — the status that grounds assurance. The universal scope ('everyone,' <em>pas</em>) removes the ethnic boundary: the same justification for Jew and God-fearer, through faith.</p>",

    "40": "<p><strong>Blepete oun mē epelthē to eirēmenon en tois prophētais</strong> ('take care that what is said in the prophets does not happen to you'): the prophets predicted both grace and judgment; the warning function belongs as much to the prophetic office as the consolation. The transition from proclamation (vv.32-39) to warning (vv.40-41) follows the prophetic pattern. Rejection of the gospel does not leave hearers where they were before hearing it; having heard places them under the prophetic warning about those who refused God's final offer.</p>",

    "41": "<p><strong>Hab 1:5 LXX</strong>: 'Look, you scoffers, wonder and perish! For I am going to do something in your days that you would never believe, even if someone told you.' In its original context Habakkuk 1:5 announces the Babylonian invasion as unbelievable divine action. Applied here, the resurrection is the 'work' in 'your days' that surpasses belief. The same text used at Qumran (1QpHab) to describe the Teacher of Righteousness's message being rejected by the wicked priest. Paul's citation closes the speech with an ominous alternative: believe something extraordinary, or become the scoffers the prophet warned about.</p>",

    "42": "<p><strong>Parakaleisthai ta rēmata tauta eis to metaxy sabbaton</strong> ('to have these words spoken to them the following Sabbath'): the congregation's invitation signals genuine interest — the first response to Paul's synagogue sermon is positive. The Lukan pattern in synagogue preaching is consistent: initial interest from the mixed audience, second-visit explosion of interest (v.44), then a split response — some believing, some opposing (vv.45-46). The pattern models the 'to the Jew first' mission strategy and its consistent outcome of division.</p>",

    "43": "<p><strong>Polloi tōn Ioudaiōn kai tōn sebomenōn prosēlytōn</strong> ('many of the Jews and devout proselytes'): <em>sebomenoi prosēlytoi</em> — full converts to Judaism who had undergone circumcision, distinct from the uncircumcised God-fearers. The response cuts across the Jewish community's internal divisions: full-born Jews, proselytes, and apparently God-fearers (v.26) all respond positively. The instruction — 'continue in the grace of God' (<em>prosmeneō tē chariti tou theou</em>) — is Paul's pastoral follow-up: the conversion is a beginning requiring sustained commitment, not a single decision.</p>",

    "44": "<p><strong>Schedon pasa hē polis synēchthē</strong> ('almost the whole city gathered'): the spread from the synagogue to the city at large within one week mirrors Pentecost — a contained gathering expanding to the entire population. 'Almost the whole city' is hyperbolic but conveys genuine social disruption: when a city's population gathers to hear a message, it is a civic event threatening established social order. The explosion of interest is the context for the Jewish leadership's jealousy (v.45) — the scale of the response threatens their social position as interpreters of Israel's Scriptures.</p>",

    "45": "<p><strong>Zēlou eplēsthēsan hoi Ioudaioi</strong> ('the Jewish leaders were filled with jealousy'): <em>zēlos</em> is the same word used for the Sanhedrin's motivation in 5:17 — 'filled with jealousy' at the apostles' success. The social explanation is clear: Paul and Barnabas, visiting outsiders, have drawn a larger crowd in one week than the local synagogue leaders might see in a year. <em>Blasphēmountes</em> ('blaspheming/slandering'): publicly discrediting Paul and Barnabas — possibly using scriptural arguments against their claims about Jesus, or social slander, or both. The jealousy-response pattern will repeat at Corinth (18:12) and Ephesus (19:8-9).</p>",

    "46": "<p><strong>Hymīn ēn anagkaion prōton lalēthēnai ton logon tou theou</strong> ('it was necessary to speak the word of God to you first'): divine necessity (<em>anagkaion</em>) — not mere strategy but divine ordering. The pivot — 'since you reject it and do not consider yourselves worthy of eternal life, we now turn to the Gentiles' — is not a rejection of Israel but a response to self-exclusion. Those who reject the message in effect pronounce their own unworthiness; the apostles accept that verdict and redirect. This pattern will repeat at Corinth (18:6) and Rome (28:25-28), each time reinforcing that the Gentile mission was initiated by Jewish refusal, not apostolic preference.</p>",

    "47": "<p><strong>Isa 49:6</strong>: 'I have made you a light for the Gentiles, that you may bring salvation to the ends of the earth.' The Servant Song's commission — originally addressed to Israel's Servant or the prophet — is here applied directly to Paul and Barnabas. Luke 2:32 had already applied this text to Jesus ('a light for Gentile revelation'); applying it to his apostles shows how the mission of Christ continues in those he sends. As apostles commissioned by the risen Christ, Paul and Barnabas share in the Servant's mission — not replacing Jesus in the text but extending his mission to the nations.</p>",

    "48": "<p><strong>Tetagmenoi eis zōēn aiōnion</strong> ('appointed/enrolled for eternal life'): <em>tassō</em> in its passive perfect participle — 'having been enrolled/appointed' (prior and completed action). The perfect tense indicates these Gentiles had already been enrolled in the divine register before they heard and believed. <em>Tassō</em> in the Hellenistic world was administrative vocabulary for civic enrollment — city rolls, military lists, tax registers. Those whose names were on the register were full members of the community; their membership preceded any individual act. The statement is theological predestination expressed in the idiom of imperial administration: God's citizenship roll is prior to human response.</p>",

    "49": "<p><strong>Diepherto de ho logos tou kyriou di' holēs tēs chōras</strong> ('the word of the Lord spread through the whole region'): the growth summary (cf. 6:7; 12:24; 19:20) places the Pisidian Antioch episode within the Acts pattern of the word's unstoppable expansion. The region (<em>chōra</em>) refers to the Galatian/Phrygian territory around Pisidian Antioch — the same region as Paul's Galatian churches. The founding mission of Acts 13-14 is the background for Galatians, where Paul defends the gospel he preached 'when he first preached' to the Galatians (Gal 4:13).</p>",

    "50": "<p><strong>Tas sebomenas gynaikas tas euschēmonas kai tous prōtous tēs poleōs</strong> ('God-fearing women of high standing and leading men of the city'): the opposition organized among the city's elite — socially prominent women who were God-fearers, and civic leading men (likely their husbands or patrons). This coalition — elite women, civic leaders, synagogue authorities — represents the full range of municipal power. The persecution is not mob violence but elite-organized expulsion: using formal civic channels to remove Paul and Barnabas from the city's territory. This mechanism of elite resistance to the early church's social disruption recurs throughout Acts.</p>",

    "51": "<p><strong>Ektinaxamenoi ton koniorton tōn podōn</strong> ('shaking the dust off their feet'): commanded by Jesus in Luke 10:10-11 ('shake the dust off your feet as a testimony against them'). The gesture derived from the Jewish practice of shaking off the dust of Gentile territory when returning to Israel — pagan dust was ritually unclean. Applied here to a Jewish city, it reverses the cultural logic: those who reject God's final message are treated as ritually unclean territory from which the messengers must be purified. Iconium was approximately 80 miles southeast of Pisidian Antioch; the mission continues without interruption.</p>",

    "52": "<p><strong>Eplērounto charas kai pneumatos hagiou</strong> ('were being filled with joy and the Holy Spirit'): the imperfect passive — continuous action — describes the ongoing state of the disciples left in Pisidian Antioch. The combination of joy and Holy Spirit as the persecuted community's characteristic state echoes Jesus's teaching in Luke 6:22-23 ('Blessed are you when people hate you... Rejoice in that day') and 1 Thess 1:6 ('you received the word in the midst of severe suffering, with the joy given by the Holy Spirit'). Persecution and joy are linked by the Spirit's presence — the chapter closes on this note before the narrative moves to Iconium.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'acts')
    merge_comm(existing, ACTS)
    save_comm('mkt-context', 'acts', existing)
    for ch in ['12', '13']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
